'use client';
import CourseForm from '@/components/CourseForm';
import { useState } from 'react';

type Course = {
  grade: number;
  credits: number;
};

export default function GPACalculatorPage() {
  const [courseGrade, setCourseGrade] = useState<number>(4.0);
  const [courseCredits, setCourseCredits] = useState<number>(3);
  const [courses, setCourses] = useState<Course[]>([]);
  const [gpa, setGpa] = useState<number | null>(null);

  const handleAddCourse = () => {
    if (courseGrade !== null && courseCredits !== null) {
      setCourses([...courses, { grade: courseGrade, credits: courseCredits }]);
      // Reset form
      setCourseGrade(4.0);
      setCourseCredits(3);
    }
  };

  const handleCalculateGPA = () => {
    if (courses.length === 0) {
      alert('Please add at least one course');
      return;
    }

    const totalGradeCredits = courses.reduce(
      (sum, course) => sum + course.grade * course.credits,
      0,
    );
    const totalCredits = courses.reduce((sum, course) => sum + course.credits, 0);
    const calculatedGPA = totalGradeCredits / totalCredits;

    setGpa(calculatedGPA);
  };

  return (
    <div>
      <main className="mx-auto flex max-w-2xl flex-col items-center px-4 py-8 text-center">
        <h1 className="text-2xl">GPA Calculator</h1>
        <h3 className="text-xl text-gray-600">Calculate your GPA on a 4.0 scale</h3>
        {/* School/major selection removed from GPA calculator; handled in SignUp */}
        <div className="w-full max-w-3xl">
          <div className="rounded-lg bg-white p-6 shadow-md">
            <div className="flex flex-col gap-6 md:flex-row">
              <div className="flex flex-col items-center md:w-1/2">
                <div className="w-full">
                  <p className="mb-2">
                    Grade: {courseGrade} | Credits: {courseCredits}
                  </p>
                  <div className="rounded-lg border p-4">
                    <CourseForm
                      grade={courseGrade}
                      credits={courseCredits}
                      setGrade={setCourseGrade}
                      setCredits={setCourseCredits}
                    />
                  </div>

                  <div className="mt-4 flex justify-center">
                    <button
                      onClick={handleAddCourse}
                      className="inline-flex items-center gap-2 rounded-full bg-green-800 px-5 py-3 text-white shadow-md hover:bg-green-800 active:scale-95"
                    >
                      <span className="text-lg">＋</span>
                      <span className="font-medium">Add Course</span>
                    </button>
                  </div>
                </div>
              </div>

              <div className="md:w-1/2">
                <div className="w-full">
                  <h3 className="text-lg font-semibold">Added Courses</h3>
                  {courses.length === 0 ? (
                    <p className="mt-2 text-sm text-gray-500">No courses added yet.</p>
                  ) : (
                    <div className="mt-3">
                      <table className="w-full border-collapse border border-gray-200">
                        <thead>
                          <tr className="bg-gray-50">
                            <th className="border border-gray-200 p-2 text-left">Grade</th>
                            <th className="border border-gray-200 p-2 text-left">Credits</th>
                          </tr>
                        </thead>
                        <tbody>
                          {courses.map((course, index) => (
                            <tr key={index}>
                              <td className="border border-gray-200 p-2">
                                {course.grade.toFixed(2)}
                              </td>
                              <td className="border border-gray-200 p-2">{course.credits}</td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  )}

                  <div className="mt-4 flex justify-center">
                    <button
                      onClick={handleCalculateGPA}
                      className="rounded-md bg-blue-800 px-4 py-2 text-white shadow hover:bg-blue-700 active:scale-95"
                    >
                      Calculate GPA
                    </button>
                  </div>

                  {gpa !== null && (
                    <div className="mt-4 flex justify-center">
                      <div className="rounded border border-green-400 bg-green-100 p-4">
                        <h2 className="text-2xl font-bold">Your GPA: {gpa.toFixed(2)}</h2>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}
